-    }
-
-    /// Normalize (remove trailing zeros)
-    pub fn normalize(self: Self) Self {
-        if (self.special != .Normal or self.coefficient == 0) return self;
-
-        var result = self;
-        while (result.coefficient % 10 == 0 and result.coefficient > 0) {
